import{bQ as d,aL as a,u as e,G as o}from"./chunks/framework.D06dwy5q.js";const p=JSON.parse('{"title":"Nacos 基础","description":"","frontmatter":{},"headers":[],"relativePath":"07.服务注册与配置中心/01-Nacos基础.md","filePath":"07.服务注册与配置中心/01-Nacos基础.md","lastUpdated":null}'),r={name:"07.服务注册与配置中心/01-Nacos基础.md"};function c(E,t,s,i,h,A){return a(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="nacos-基础" tabindex="-1">Nacos 基础 <a class="header-anchor" href="#nacos-基础" aria-label="Permalink to &quot;Nacos 基础&quot;">​</a></h1><p>单体应用时代这些问题不明显：一个应用、一个配置文件、一个数据库连接，启动脚本里写死就行。服务拆多以后，订单服务有多台实例，库存服务也有多台实例，某个实例发布重启后 IP 和端口可能完全变了；同时，连接池大小、限流开关、灰度参数这些配置又不适合每次都登录机器改文件再重启。Nacos 解决的就是这两类问题：&quot;服务地址会变化&quot;和&quot;配置需要集中变更&quot;。</p><p>Nacos 的全称是 Dynamic <strong>Na</strong>ming and <strong>Co</strong>nfiguration <strong>S</strong>ervice，名字已经标出了两条核心能力：</p><table tabindex="0"><thead><tr><th>能力</th><th>做什么</th><th>常见场景</th></tr></thead><tbody><tr><td>Naming（服务注册与发现）</td><td>服务实例的登记和查询</td><td><code>order-service</code> 下面当前有哪些可用的 IP:PORT</td></tr><tr><td>Configuration（配置中心）</td><td>配置的保存、发布、监听和回滚</td><td><code>application.yaml</code> 改了之后应用读到新值</td></tr></tbody></table><h2 id="一、运维视角下的组件构成" tabindex="-1">一、运维视角下的组件构成 <a class="header-anchor" href="#一、运维视角下的组件构成" aria-label="Permalink to &quot;一、运维视角下的组件构成&quot;">​</a></h2><p>从运维角度看，Nacos 不只是浏览器里那个控制台页面。它至少包含这几部分：</p><table tabindex="0"><thead><tr><th>部分</th><th>做什么</th><th>部署依赖</th></tr></thead><tbody><tr><td>Nacos Server</td><td>提供配置、注册、查询、推送接口的服务端进程</td><td>Java 17+、端口、配置文件</td></tr><tr><td>控制台</td><td>人在浏览器里查看和修改配置、服务、权限、集群状态</td><td><code>8080</code> 端口</td></tr><tr><td>客户端 SDK</td><td>业务应用用它注册实例、读取配置、监听变更</td><td>应用侧的 <code>nacos-client</code> 依赖</td></tr><tr><td>MySQL</td><td>保存配置内容、用户账号、权限、历史版本</td><td>集群模式必须依赖外部数据库</td></tr><tr><td>集群通信</td><td>多个 Nacos 节点之间同步状态、保持一致性</td><td>gRPC 和 Raft 端口互通</td></tr></tbody></table><p>控制台能登录只说明管理入口可用；业务应用还要能连到服务端 API、通过鉴权、注册实例、读取配置——这几个环节跟控制台是不同的端口和路径。排错时容易卡在&quot;控制台页面一切正常，但应用那边配置读不到、服务注册不上&quot;之间。</p><h2 id="二、在整个架构里的位置" tabindex="-1">二、在整个架构里的位置 <a class="header-anchor" href="#二、在整个架构里的位置" aria-label="Permalink to &quot;二、在整个架构里的位置&quot;">​</a></h2><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20user%5B%22%E7%94%A8%E6%88%B7%E8%AF%B7%E6%B1%82%22%5D%20--%3E%20gateway%5B%22%E7%BD%91%E5%85%B3%20%2F%20Nginx%22%5D%0A%20%20%20%20gateway%20--%3E%20app1%5B%22%E4%B8%9A%E5%8A%A1%E6%9C%8D%E5%8A%A1%20A%22%5D%0A%20%20%20%20gateway%20--%3E%20app2%5B%22%E4%B8%9A%E5%8A%A1%E6%9C%8D%E5%8A%A1%20B%22%5D%0A%0A%20%20%20%20app1%20--%3E%20nacos%5B%22Nacos%3Cbr%2F%3E%E6%9C%8D%E5%8A%A1%E5%8F%91%E7%8E%B0%20%2F%20%E9%85%8D%E7%BD%AE%E4%B8%AD%E5%BF%83%22%5D%0A%20%20%20%20app2%20--%3E%20nacos%0A%20%20%20%20nacos%20--%3E%20db%5B%22MySQL%3Cbr%2F%3E%E9%85%8D%E7%BD%AE%E5%92%8C%E6%9D%83%E9%99%90%E6%95%B0%E6%8D%AE%22%5D%0A"></div><p>请求进系统时先经过网关或 Nginx，Nacos 在旁边提供&quot;查服务地址&quot;和&quot;取配置&quot;的能力。调用方拿到实例列表后，请求由客户端框架直接发给目标实例——不会每次都穿过 Nacos。这个位置决定了排查时的优先级：接口 502、网关超时、Pod 网络不通，第一现场通常在入口或网络层；如果服务列表里缺实例、配置没下发、客户端启动时就报 Nacos 连接异常，再回到 Nacos 排查。</p><h2 id="三、服务注册与发现的交互方式" tabindex="-1">三、服务注册与发现的交互方式 <a class="header-anchor" href="#三、服务注册与发现的交互方式" aria-label="Permalink to &quot;三、服务注册与发现的交互方式&quot;">​</a></h2><p>服务提供方把自己的地址登记到 Nacos，调用方向 Nacos 查询服务名下有哪些可用实例：</p><div class="mermaid-diagram" data-mermaid-code="sequenceDiagram%0A%20%20%20%20participant%20P%20as%20%22%E6%9C%8D%E5%8A%A1%E6%8F%90%E4%BE%9B%E6%96%B9%22%0A%20%20%20%20participant%20N%20as%20%22Nacos%22%0A%20%20%20%20participant%20C%20as%20%22%E6%9C%8D%E5%8A%A1%E8%B0%83%E7%94%A8%E6%96%B9%22%0A%0A%20%20%20%20P-%3E%3EN%3A%20%22%E6%B3%A8%E5%86%8C%3A%20order-service%20%2F%20192.168.10.21%3A8080%22%0A%20%20%20%20C-%3E%3EN%3A%20%22%E6%9F%A5%E8%AF%A2%20order-service%20%E7%9A%84%E5%AE%9E%E4%BE%8B%22%0A%20%20%20%20N--%3E%3EC%3A%20%22%E8%BF%94%E5%9B%9E%E5%AE%9E%E4%BE%8B%E5%88%97%E8%A1%A8%22%0A%20%20%20%20C-%3E%3EP%3A%20%22%E6%8C%89%E5%AE%A2%E6%88%B7%E7%AB%AF%E8%B4%9F%E8%BD%BD%E5%9D%87%E8%A1%A1%E7%9B%B4%E6%8E%A5%E8%B0%83%E7%94%A8%22%0A"></div><p>服务和实例是两个不同的对象。服务是逻辑名称，比如 <code>order-service</code>；实例是具体的进程地址，比如 <code>192.168.10.21:8080</code>。一个服务下面可以有多个实例，发布、扩容、缩容、机器故障时实例列表会变化。</p><p>服务发现的常见字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>含义</th><th>示例</th></tr></thead><tbody><tr><td>服务名</td><td>逻辑服务名称</td><td><code>order-service</code></td></tr><tr><td>分组</td><td>服务分组</td><td><code>DEFAULT_GROUP</code></td></tr><tr><td>命名空间</td><td>环境或租户隔离</td><td><code>public</code>、<code>prod</code></td></tr><tr><td>实例 IP/端口</td><td>具体进程地址</td><td><code>192.168.10.21:8080</code></td></tr><tr><td>健康状态</td><td>是否可被调用</td><td><code>healthy=true</code></td></tr><tr><td>权重</td><td>客户端选择实例时的参考</td><td><code>1.0</code></td></tr><tr><td>元数据</td><td>版本、机房、灰度标签等附加信息</td><td><code>version=v2</code></td></tr></tbody></table><p>Nacos 里有<strong>临时实例</strong>和<strong>持久实例</strong>的区别。普通微服务进程大多是临时实例——由客户端 SDK 保持心跳，进程停了、心跳断了，实例被标记为不健康然后摘除。持久实例更像一条人工维护的固定记录，不会因为客户端连接断开就自动消失，适合少量固定后端或需要手动管理的服务条目。</p><h2 id="四、客户端如何感知实例变化" tabindex="-1">四、客户端如何感知实例变化 <a class="header-anchor" href="#四、客户端如何感知实例变化" aria-label="Permalink to &quot;四、客户端如何感知实例变化&quot;">​</a></h2><p>服务实例列表不是静态的——发布、扩容、机器宕机都会让它变化。Nacos 让调用方保持最新列表的方式有两种：</p><table tabindex="0"><thead><tr><th>方式</th><th>怎么做</th><th>适用场景</th></tr></thead><tbody><tr><td>客户端定时拉取</td><td>SDK 每隔一段时间主动查询最新实例列表</td><td>实例变化不频繁、对实时性要求不高</td></tr><tr><td>服务端推送变更</td><td>Nacos 检测到实例变化后，通过 gRPC 长连接推给订阅了该服务的客户端</td><td>需要快速感知实例上下线</td></tr></tbody></table><p>实际运行时两种方式会配合使用：正常情况下靠推送，客户端同时保留定时拉取作为兜底——即使推送链路断了，定时拉取还能保证最终拿到新列表。</p><h2 id="五、配置中心的三段定位" tabindex="-1">五、配置中心的三段定位 <a class="header-anchor" href="#五、配置中心的三段定位" aria-label="Permalink to &quot;五、配置中心的三段定位&quot;">​</a></h2><p>配置中心保存应用的运行配置，YAML、properties、JSON、纯文本都可以。一份配置靠三段组合来定位：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>namespace + group + dataId</span></span></code></pre></div><table tabindex="0"><thead><tr><th>字段</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td><code>namespace</code></td><td>命名空间，常用于环境隔离</td><td><code>public</code>、<code>dev</code>、<code>prod</code></td></tr><tr><td><code>group</code></td><td>分组，同一命名空间内进一步分组</td><td><code>DEFAULT_GROUP</code></td></tr><tr><td><code>dataId</code></td><td>配置标识，习惯写成文件名形式</td><td><code>application.yaml</code></td></tr></tbody></table><p>配置发布后 Nacos 会推送变更通知给监听该配置的客户端。但应用能不能热更新，取决于客户端框架和业务代码——Nacos 只负责推送，&quot;推送到了&quot;和&quot;业务变量已经换成新值&quot;之间有距离。启动配置（数据源、端口等）通常需要重启；动态配置（开关、阈值、灰度比例）如果应用框架支持且代码写了监听，可以运行时生效。</p><p>配置中心几个核心运维价值：</p><table tabindex="0"><thead><tr><th>能力</th><th>解决什么问题</th></tr></thead><tbody><tr><td>集中发布</td><td>不用登机器改文件，一个入口管理所有环境配置</td></tr><tr><td>历史版本</td><td>知道什么时候谁改了什么东西，改之前内容是什么</td></tr><tr><td>回滚</td><td>改错了可以退回到之前任一版本</td></tr><tr><td>权限控制</td><td>控制谁能改生产配置</td></tr><tr><td>变更推送</td><td>应用实时感知配置变化，不用重启</td></tr></tbody></table><h2 id="六、namespace、group、dataid-的实例" tabindex="-1">六、namespace、group、dataId 的实例 <a class="header-anchor" href="#六、namespace、group、dataid-的实例" aria-label="Permalink to &quot;六、namespace、group、dataId 的实例&quot;">​</a></h2><p>三者组合起来可以同时支持多个环境和多个业务线：</p><table tabindex="0"><thead><tr><th>namespace</th><th>group</th><th>dataId</th><th>含义</th></tr></thead><tbody><tr><td><code>dev</code></td><td><code>DEFAULT_GROUP</code></td><td><code>order-service.yaml</code></td><td>开发环境订单服务配置</td></tr><tr><td><code>prod</code></td><td><code>DEFAULT_GROUP</code></td><td><code>order-service.yaml</code></td><td>生产环境订单服务配置</td></tr><tr><td><code>prod</code></td><td><code>PAY_GROUP</code></td><td><code>pay-service.yaml</code></td><td>生产环境支付服务配置</td></tr></tbody></table><p>&quot;配置读不到&quot;时，namespace、group、dataId 三段必须对照。比如控制台里能看到 <code>prod / DEFAULT_GROUP / order-service.yaml</code>，但应用启动参数里写的是 <code>namespace=dev</code>，客户端日志里又打印 <code>dataId=order-service.yaml, group=DEFAULT_GROUP</code>，基本能判断应用连到了 dev 命名空间，读不到 prod 那份配置。</p><p>整个配置管理的交互过程大致如下：</p><div class="mermaid-diagram" data-mermaid-code="sequenceDiagram%0A%20%20%20%20participant%20O%20as%20%22%E8%BF%90%E7%BB%B4%20%2F%20%E5%BC%80%E5%8F%91%22%0A%20%20%20%20participant%20N%20as%20%22Nacos%22%0A%20%20%20%20participant%20DB%20as%20%22MySQL%22%0A%20%20%20%20participant%20A%20as%20%22%E4%B8%9A%E5%8A%A1%E5%BA%94%E7%94%A8%20A%22%0A%20%20%20%20participant%20B%20as%20%22%E4%B8%9A%E5%8A%A1%E5%BA%94%E7%94%A8%20B%22%0A%0A%20%20%20%20O-%3E%3EN%3A%20%22%E5%8F%91%E5%B8%83%E6%88%96%E4%BF%AE%E6%94%B9%E9%85%8D%E7%BD%AE%22%0A%20%20%20%20N-%3E%3EDB%3A%20%22%E5%86%99%E5%85%A5%E9%85%8D%E7%BD%AE%E5%86%85%E5%AE%B9%E5%92%8C%E5%8E%86%E5%8F%B2%E7%89%88%E6%9C%AC%22%0A%20%20%20%20N--%3E%3EA%3A%20%22%E6%8E%A8%E9%80%81%E5%8F%98%E6%9B%B4%E9%80%9A%E7%9F%A5%22%0A%20%20%20%20N--%3E%3EB%3A%20%22%E6%8E%A8%E9%80%81%E5%8F%98%E6%9B%B4%E9%80%9A%E7%9F%A5%22%0A%20%20%20%20A-%3E%3EA%3A%20%22%E5%88%B7%E6%96%B0%E6%9C%AC%E5%9C%B0%E9%85%8D%E7%BD%AE%EF%BC%88%E5%8F%96%E5%86%B3%E4%BA%8E%E6%A1%86%E6%9E%B6%E5%92%8C%E4%BB%A3%E7%A0%81%EF%BC%89%22%0A%20%20%20%20B-%3E%3EB%3A%20%22%E5%88%B7%E6%96%B0%E6%9C%AC%E5%9C%B0%E9%85%8D%E7%BD%AE%EF%BC%88%E5%8F%96%E5%86%B3%E4%BA%8E%E6%A1%86%E6%9E%B6%E5%92%8C%E4%BB%A3%E7%A0%81%EF%BC%89%22%0A"></div><p>这段过程里最容易出问题的环节是两个：推送是否到达（网络、客户端连接状态），以及到达后应用是否真的刷新了（框架支持、代码监听）。</p><h2 id="七、和-kubernetes-service-的关系" tabindex="-1">七、和 Kubernetes Service 的关系 <a class="header-anchor" href="#七、和-kubernetes-service-的关系" aria-label="Permalink to &quot;七、和 Kubernetes Service 的关系&quot;">​</a></h2><p>两者都能让应用找到服务，但不在同一层：</p><table tabindex="0"><thead><tr><th>对比项</th><th>Nacos</th><th>Kubernetes Service</th></tr></thead><tbody><tr><td>所在层</td><td>应用层服务发现 + 配置管理</td><td>集群网络抽象</td></tr><tr><td>使用方式</td><td>客户端 SDK 查服务读配置</td><td>Pod 通过 DNS 或 ClusterIP 访问</td></tr><tr><td>注册对象</td><td>服务名、实例、配置、元数据</td><td>Service、EndpointSlice、Pod</td></tr><tr><td>配置管理</td><td>内置，带版本和回滚</td><td>ConfigMap / Secret，无版本概念</td></tr><tr><td>常见体系</td><td>Spring Cloud Alibaba</td><td>K8s 原生工作负载</td></tr></tbody></table><p>K8s 里也可以跑 Nacos。Spring Cloud 应用已经深度依赖 Nacos 做服务发现和配置中心时，迁到 K8s 后通常保留 Nacos，K8s Service 负责集群网络入口。两者可以并存，职责不同。新项目如果全跑在 K8s 里，是否继续用 Nacos 取决于团队技术栈、配置管理的复杂度、灰度能力需求和对 Nacos 的运维成本。</p><h2 id="八、nacos-3-x-的几个关键变化" tabindex="-1">八、Nacos 3.x 的几个关键变化 <a class="header-anchor" href="#八、nacos-3-x-的几个关键变化" aria-label="Permalink to &quot;八、Nacos 3.x 的几个关键变化&quot;">​</a></h2><p>实验使用的 Nacos 3.2.1 和旧版资料有几处差异：</p><table tabindex="0"><thead><tr><th>项</th><th>Nacos 3.2.1 实际情况</th></tr></thead><tbody><tr><td>控制台端口</td><td>默认 <code>8080</code>（旧版是 <code>8848/nacos</code>）</td></tr><tr><td>服务端 API 端口</td><td><code>8848</code>，<code>/nacos</code> 路径</td></tr><tr><td>Java 版本</td><td>需要 Java 17+</td></tr><tr><td>API 版本</td><td>新接口以 <code>/v3</code> 为主，旧 <code>/v1</code> 资料不能完全照搬</td></tr><tr><td>鉴权</td><td>启动脚本对鉴权配置项检查更严格，Token Secret 等必须有效填充</td></tr></tbody></table><p>旧资料经常直接访问 <code>8848/nacos</code> 打开控制台，Nacos 3.x 会提示控制台改到了 <code>8080/next/</code>。<code>8848</code> 更偏服务端 API 和客户端通信入口。</p><h2 id="九、运维关注点总览" tabindex="-1">九、运维关注点总览 <a class="header-anchor" href="#九、运维关注点总览" aria-label="Permalink to &quot;九、运维关注点总览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方向</th><th>关注什么</th></tr></thead><tbody><tr><td>部署</td><td>Java 版本、端口、启动参数、systemd、集群文件</td></tr><tr><td>存储</td><td>MySQL 连接、表结构、备份、schema 版本匹配</td></tr><tr><td>配置</td><td><code>namespace/group/dataId</code> 三段对齐、历史版本、回滚、灰度</td></tr><tr><td>服务</td><td>临时/持久实例、心跳、健康状态、权重、元数据</td></tr><tr><td>集群</td><td>节点状态、端口互通、版本一致、cluster.conf</td></tr><tr><td>权限</td><td>登录账号、Token、鉴权参数三节点一致性</td></tr><tr><td>排错</td><td>客户端连接、配置不生效、服务掉线、节点异常</td></tr></tbody></table><p>控制台正常不等于业务正常。控制台是给人看的，服务端 API 和客户端通信才是应用真正依赖的。</p>',47)])])}const l=d(r,[["render",c]]);export{p as __pageData,l as default};
